#include <stdio.h>
#include "riscv_nn_convolution.h"

#define IN_DIM_X 16
#define IN_DIM_Y 16
#define IN_CH 512
#define OUT_CH 32
#define KER_DIM_X 1
#define KER_DIM_Y 1
#define PAD_X 0
#define PAD_Y 0
#define STRIDE_X 1
#define STRIDE_Y 1
#define PRE_RSFT 6
#define OUT_SCALE 3
#define POST_RSFT 5
#define OUT_DIM_X 16
#define OUT_DIM_Y 15
#define SRC1_LEN (IN_CH * IN_DIM_X * IN_DIM_Y)
#define SRC2_LEN  (OUT_CH * IN_CH * KER_DIM_X * KER_DIM_Y)
#define BUF_LEN (IN_CH * KER_DIM_X * KER_DIM_Y * 2)
#define OUT_LEN (OUT_CH * OUT_DIM_X * OUT_DIM_Y)

q7_t src1[SRC1_LEN] FUNC_ATTR_ALIGN;
q7_t src2[SRC2_LEN] FUNC_ATTR_ALIGN;
q15_t out[OUT_LEN] FUNC_ATTR_ALIGN;
q15_t in_tmp_buf[BUF_LEN] FUNC_ATTR_ALIGN;
q31_t bias[OUT_CH] FUNC_ATTR_ALIGN;
#if !ENA_RANDOM_INPUT
q15_t golden[OUT_LEN];
#endif

int main (void)
{
    enable_fs_and_vs();
    uint32_t retStatus=NDS_SUCCESS;

#if ENA_RANDOM_INPUT
    uint32_t i;
    for(i=0; i<SRC1_LEN; i++)
    {
        src1[i] = rand();
    }
    for(i=0; i<SRC2_LEN; i++)
    {
        src2[i] = rand();
    }
    for(i=0; i<OUT_CH; i++)
    {
        bias[i] = rand();
    }
#else
    FILE *fptr_src1, *fptr_src2, *fptr_bias;
    test_Fopen("8b_in1.bin", "rb", &fptr_src1);
    test_Fopen("8b_in2.bin", "rb", &fptr_src2);
    test_Fopen("32b_in1.bin", "rb", &fptr_bias);
    test_Fread(src1, sizeof(*src1), SRC1_LEN, fptr_src1, "src1");
    test_Fread(src2, sizeof(*src2), SRC2_LEN, fptr_src2, "src2");
    test_Fread(bias, sizeof(*bias), OUT_CH, fptr_bias, "bias");
    fclose(fptr_src1);
    fclose(fptr_src2);
    fclose(fptr_bias);
#endif

#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_conv_1x1_HWC_s8_s16_s8_sym_bias_fast_any(src1, IN_DIM_X, IN_DIM_Y, IN_CH, src2, OUT_CH, KER_DIM_X, KER_DIM_Y, PAD_X, PAD_Y, STRIDE_X, STRIDE_Y, bias, PRE_RSFT, OUT_SCALE, POST_RSFT, out, OUT_DIM_X, OUT_DIM_Y, in_tmp_buf);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if !ENA_RANDOM_INPUT
    FILE *fptr_golden;
    test_Fopen("conv_1x1_HWC_q7_q15_fast_any_bias_2sft_golden3.bin", "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), OUT_LEN, fptr_golden, "golden");
    uint32_t maxDiff = verify_buffer(out, golden, OUT_LEN, sizeof(*golden));
    if (maxDiff != 0)
    {
        printf("accuracy checking fail\n\n");
        retStatus |= NDS_FAILURE;
    }
    else
    {
        printf("accuracy checking pass\n\n");
        retStatus |= NDS_SUCCESS;
    }
    fclose(fptr_golden);
#endif

    return retStatus;
}

